changeSet.sql:
create extension if not exists btree_gin;
create index if not exists ix_jsonb_search_data
	on jsonb_document_fields using gin (model_name, search_data gin_trgm_ops);

alter table document_fields add number_value numeric, add timestamp_value timestamp, add ts_range_value tsrange;
create extension if not exists btree_gist;
create index idx_document_fields_number_value on document_fields (field_name, number_value, doc_ref) where number_value is not null;
create index idx_document_fields_ts_range_value on document_fields using gist (field_name, ts_range_value, doc_ref) where ts_range_value is not null;
create index idx_document_fields_ts_value on document_fields (field_name, timestamp_value, doc_ref) where timestamp_value is not null

drop index if exists idx_document_fields_name;
drop index if exists idx_document_fields_doc_ref;
drop index if exists idx_document_fields_value_insensitive;
drop index if exists idx_document_fields_value;
drop index if exists idx_document_fields_doc_ref_single;
drop index if exists idx_substring_match_insensitive;
drop index if exists idx_value_field_name;
drop index if exists idx_document_fields_typed_value;
drop index if exists idx_typed_value_field_name;
drop trigger if exists createfulltexttrigger on document_fields;

drop index if exists idx_document_search_original_value;
create index if not exists idx_document_search_original_value_search_data
	on document_search using gin (model_name, original_value, search_data gin_trgm_ops);
